(window.courseContentFiles = window.courseContentFiles || {})["000002/0008"] = "<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Изследвания в Пулмологията</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body { \n      font-family: \"Open Sans\", Arial, sans-serif; \n      max-width: 1550px; \n      margin: 0.5rem auto; \n      padding: 0 1rem; \n      line-height: 1.6; \n      color: #1f2937; \n    }\n    h1, h2, h3, h4 { \n      font-weight: 600; \n      margin-top: 0.8em;\n      margin-bottom: 0.15em;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0.1em; }\n    h4 { font-size: 1.05em; margin-bottom: 0.1em; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.2em; }\n    p { \n      margin: 0.3em 0; \n      white-space: pre-wrap;\n    }\n    p + ul, p + ol { margin-top: -0.5em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol { \n      margin-top: 0.1em; \n    }\n    ul, ol { \n      margin: 0.5em 0; \n      padding-left: 1.5em; \n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.3em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.2em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code { \n      background: rgba(218, 215, 205, 0.3); \n      padding: 2px 6px; \n      border-radius: 3px; \n      font-family: \"Courier New\", monospace; \n      font-size: 0.9em; \n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table { \n      border-collapse: collapse; \n      margin: 0.75em 0; \n      width: 100%; \n      table-layout: auto;\n    }\n    th, td { \n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px; \n      text-align: left; \n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th { \n      background: rgba(88, 129, 87, 0.13); \n      font-weight: 600; \n    }\n    tbody tr:nth-child(odd) { \n      background: rgba(88, 129, 87, 0.06); \n    }\n    /* Image styles are handled by inline styles and data-width attributes */\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n      line-height: 1 !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.3em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.2em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 768px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.3em; }\n      h2 { font-size: 1.1em; }\n      h3 { font-size: 1em; }\n      p { margin: 0.5em 0; }\n      ul, ol { padding-left: 1.2em; }\n      li { margin: 0.1em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 4px 6px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n        \n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n        \n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n          \n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n          \n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n          \n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n            \n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n              \n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n        \n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n        \n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n        \n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n        \n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<h1 style=\"text-align: center\">Обективно изследване на белите дробове</h1><h2>Оглед на гръдния кош</h2><h3>Статичен Оглед (Симетричност)</h3><p>Сравнява се симетрията на гръдния кош в инспириум и експириум.</p><table><tbody><tr><td><strong><font color=\"#588157\">Находка</font></strong></td><td><strong><font color=\"#588157\">Стеснение на едната гръдна половина</font></strong></td><td><strong><font color=\"#588157\">Разширение на едната гръдна половина</font></strong></td></tr><tr><td><strong>Причини</strong></td><td>Ателектаза на главен бронх<br>Оперативно премахване на белия дроб<br>Масивни плеврални сраствания<br>Изразена пневмофиброза</td><td>Масивен плеврален излив<br>Вентилен пневмоторакс<br>Голяма обемна лезия/тумор</td></tr></tbody></table><h3>Динамичен Оглед (Дихателна Подвижност)</h3><p>Наблюдение на дишането - <strong>намалена дихателна подвижност:</strong> </p><ul><li><strong>Масивен излив/Ателектаза/Сраствания</strong>: Пречат на нормалното разширяване на белия дроб и гръдната стена.</li><li><strong>Фрактура/Невралгия/Herpes zoster</strong>: Дишането е болезнено, което води до волево ограничаване на движението от страна на пациента.</li></ul><hr><h2>Палпация на гръден кош</h2><h3>Гласен Фремитус (Pectoral Fremitus)</h3><p>Изследва се чрез <strong>поставяне на дланите симетрично върху гръдния кош</strong>, докато пациентът произнася думи с „р“ (напр. <em>„тридесет и три“</em>). </p><p><strong>Логика:</strong> Звуковите вибрации се <strong>провеждат най-добре през плътна, хомогенна белодробна тъкан</strong>, а <strong>по-слабо през въздух или течност</strong>.</p><table><tbody><tr><td><strong><font color=\"#588157\">Находка</font></strong></td><td><strong><font color=\"#588157\">Усилен Гласен Фремитус</font></strong></td><td><strong><font color=\"#588157\">Намален Гласен Фремитус</font></strong></td></tr><tr><td><strong>Причини</strong></td><td><strong>Пневмония</strong> <br>Дренирани бронхиектазии<br>Каверна или абсцес, свързани с проходим бронх<br>Отворен пневмоторакс</td><td>Масивен плеврален излив/сраствания<br>Обструктивна ателектаза<br>Белодробен тумор<br>Затворен пневмоторакс<br>Затлъстяване</td></tr></tbody></table><h3>Подкожен Емфизем</h3><ul><li><strong>Развитие:</strong> При разкъсване на белите дробове и плеврата (травма), белодробен емфизем или тумор.</li><li><strong>Палпация:</strong> Звук, подобен на този при стискане на <strong>снежна топка</strong>.</li></ul><hr><h2>Перкусия на белите дробове</h2><h4>Сравнителна Перкусия</h4><table><tbody><tr><td><strong><font color=\"#588157\">Тон</font></strong></td><td><strong><font color=\"#588157\">Клинично Значение</font></strong></td><td><strong><font color=\"#588157\">Примери</font></strong></td></tr><tr><td><strong>Тъп</strong></td><td>Показва <strong>намалена или липсваща въздухоносност</strong> на подлежащата тъкан, най-често поради <strong>инфилтрация, колапс или течност</strong>.</td><td><strong>Лобарна пневмония</strong><br>Плеврален излив<br>Белодробен рак <br>Инфилтративна туберкулоза<br>Масивни плеврални сраствания</td></tr><tr><td><strong>Тимпаничен</strong></td><td>Показва <strong>повишено въздушно съдържание в ограничена кухина</strong> (в кухина с еластични стени).<br>Тонът е <strong>по-звучен и по-висок</strong>, отколкото при нормалния белодробен.</td><td>Белодробен абсцес <br>Туберкулозна каверна<br>Разпаднал се карцином<br>Изхранена ехинококова киста</td></tr><tr><td><strong>Хиперсонорен</strong></td><td>Свързан с <strong>дифузно повишено въздушно съдържание</strong> в белите дробове (без кухини).<br>Звукът е <strong>по-нисък и продължителен</strong> от нормалния.</td><td>Хронична обструктивна белодробна болест (<strong>ХОББ</strong>)<br>Пристъп на бронхиална астма</td></tr></tbody></table><h3>Определяне на Респираторна Подвижност</h3><ul><li><strong>Метод:</strong> Става по скапуларната линия към белодробните основи до преминаването от ясен в притъпен перкуторен тон</li><li><strong>Големина:</strong> Нормално 3–4 см. Намалява при емфизем, сраствания, плеврален излив.</li></ul><hr><h2>Аускултация на белите дробове</h2><h3>Основни Дихателни Шумове</h3><table><tbody><tr><td><strong><font color=\"#588157\">Дишане</font></strong></td><td><strong><font color=\"#588157\">Причини</font></strong></td></tr><tr><td><strong>Отслабено везикуларно</strong></td><td>Емфизем<br>Начални и крайни стадии на възпалително процеси<br>Стеноза на голям бронх<br>Плеврален излив/сраствания<br>Пневмоторакс</td></tr><tr><td><strong>Отслабено с удължено издишване</strong></td><td>Бронхиална астма<br>Белодробен емфизем (ХОББ).</td></tr><tr><td><strong>Грубо везикуларно</strong></td><td>Остър и хроничен бронхит</td></tr><tr><td><strong>Класическо Бронхиално</strong></td><td><strong>Лобарна пневмония</strong><br>Конфлуираща бронхопневмония</td></tr><tr><td><strong>Кавернозно Бронхиално</strong></td><td>Каверни (кухини), вентилирани от свободен бронх</td></tr><tr><td><strong>Плеврално Бронхиално</strong></td><td>На горната граница на големи плеврални изливи (Линия на Damoiseau)</td></tr><tr><td><strong>Липсващо дишане</strong></td><td>Плеврален излив<br>Пневмоторакс <br>Фиброторакс<br>Ателектаза</td></tr></tbody></table><h3>Допълнителни Дихателни Шумове</h3><table><tbody><tr><td><strong><font color=\"#588157\">Тип Хрип</font></strong></td><td><strong><font color=\"#588157\">Характеристики и Произход</font></strong></td><td><strong><font color=\"#588157\">Клинично Значение и Локализация</font></strong></td><td><strong><font color=\"#588157\">Примери от Учебника</font></strong></td></tr><tr><td><strong>Сухи хрипове</strong></td><td>Възникват при преминаване на въздуха през <strong>стеснен</strong> бронхиален лумен поради <strong>спазъм</strong>, <strong>оток</strong> или <strong>жилав секрет</strong> по бронхиалната стена. <br><strong>Повлияват се от кашлица</strong>.</td><td>Обикновено <strong>разпръснати двустранно</strong>.</td><td><strong>Остър и хроничен бронхит</strong> <br>(натрупване на жилав секрет)<br> <strong>Бронхиална астма и ХОББ</strong><br>(възпаление, спазъм, секрети)<br> <strong>Белодробен карцином</strong> <br>(инфилтрация или притискане на бронха отвън).</td></tr><tr><td><strong>Влажни хрипове</strong> (Едри, Средни, Дребни)</td><td>Причинени от <strong>въздух, преминаващ през течност/секрет</strong> в бронхиалния лумен.<br><strong>Дребните влажни хрипове</strong> могат да наподобяват <strong>крепитации</strong>, но <strong>изчезват след кашлица</strong>.</td><td>Могат да бъдат: <br><strong>1. Двустранни</strong> (при дифузни процеси). <br><strong>2. Ограничени</strong> (при локални лезии).</td><td><strong>Двустранни:</strong> двустранна бронхопневмония, белодробен сърдечен застой, бронхит.<br><strong>Ограничени:</strong> белодробен абсцес, бронхиектазии, туберкулоза.</td></tr><tr><td><strong>Крепитации</strong></td><td><strong>Финни, експлозивни, еднотипни звуци</strong> в <strong>края на инспириума</strong>, причинени от <strong>внезапно отваряне на слепнали алвеоли</strong>, съдържащи ексудат.<br><strong>Не се влияят от кашлица</strong>.</td><td>Показват <strong>алвеоларно</strong> засягане.<br></td><td>Пневмония (crepitatio indux/redux) <br>Бронхопневмония<br>Белодробен оток<br>Ателектаза (частична)<br>Белодробна фиброза</td></tr></tbody></table><h3>Плеврално Триене</h3><ul><li><strong>Произход:</strong> Сух плеврит, пневмония, белодробен инфаркт, уремия, лупус.</li><li><strong>Характеристики:</strong> Чува се в <strong>двете фази</strong> на дишането, звучи <strong>повърхностно</strong> (близо до ухото), <strong>усилва се при натиск</strong> със стетоскопа.</li></ul><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\"><h1 style=\"text-align: center\">Спирометрия и функционални изследване на белите дробове</h1><h2>Видове Изследвания</h2><ul><li><strong>Бавна Спирометрия:</strong> Пациентът издишва бавно (от ТБК до ОО) и обратно. Определя се <strong>Виталният Капацитет (ВК)</strong>.</li><li><strong>Форсирана Спирометрия:</strong> Пациентът вдишва до ТБК и издишва <strong>бързо, енергично и продължително</strong>. Резултатите се представят като дебит-обем и обем-време криви, даващи информация за <strong>съпротивлението</strong> (респ. за проходимостта) и <strong>динамичните възможности</strong> на дихателната система.</li></ul><hr><h2>Изпълнение на Форсирания Маньовър</h2><ol><li>Проверка на калибрацията на спирометъра.</li><li>Обяснение на теста и</li><li>Подготовка на пациента: въпроси относно тютюнопушене, медикаменти, скорошни заболявания.</li><li>Инструкции: Демонстрация на щипка за нос и мундщук. Позиция на главата (леко повдигната брадичка).</li><ul><li>\"Вдишайте толкова силно, колкото можете, поставете мундщука в устата, издишайте силно и бързо, колкото можете.\"</li></ul></ol><hr><h2>Критерии за Приемливост и Възпроизводимост</h2><table><tbody><tr><td><strong><font color=\"#588157\">Критерий</font></strong></td><td><strong><font color=\"#588157\">Описание</font></strong></td></tr><tr><td><strong>Приемливост</strong></td><td>Липса на артефакти (колеблив старт, лош пик, субмаксимално усилие, кашлица).<br>Продължителност по-голяма от <strong>6 секунди</strong>.</td></tr><tr><td><strong>Възпроизводимост</strong> (от 3 приемливи опита)</td><td>Две от най-големите измервания на <strong>ФВК</strong> да не се различават с повече от <strong>0.200 л</strong>.<br>Две от най-големите измервания на <strong>ФЕО1</strong> да не се различават с повече от <strong>0.200 л</strong>.</td></tr></tbody></table><hr><h2>Изследвани Параметри и Дефекти</h2><h3>Основни Параметри на Форсираната Спирометрия</h3><table><tbody><tr><td><strong><font color=\"#588157\">Параметър</font></strong></td><td><strong><font color=\"#588157\">Описание</font></strong></td><td><strong><font color=\"#588157\">Клинично Значение</font></strong></td></tr><tr><td><strong>ФЕО₁</strong> (Форсиран експираторен обем за 1 сек.)</td><td>Отразява механичните свойства на <strong>големите и средните бронхи</strong>.</td><td>Намален при <strong>обструкция</strong> (диспропорционално на ФВК - намален индекс на Тифно) и при <strong>рестрикция</strong>. Индикатор за ограничение на въздушния поток.</td></tr><tr><td><strong>ФВК</strong> (Форсиран витален капацитет)</td><td>Мярка за \"мобилизирания\" белодробен обем при форсирана експирация.</td><td>Намален при: <strong>\"Малки дробове\"</strong> (рестрикция) и <strong>\"Големи дробове\"</strong> (емфизем – поради блокиран газ и увеличен ОО).<br> <strong>Сам по себе си не диагностицира</strong> типа нарушение.</td></tr><tr><td><strong>ФЕО1/ФВК%</strong> (Индекс на Тифно)</td><td>Отношението между ФЕО₁ и ФВК.</td><td>Използва се за <strong>разграничаване</strong> на обструктивен от рестриктивен дефект.</td></tr></tbody></table><h3>Вентилаторни Дефекти</h3><ul><li><strong>Обструктивен Вентилаторен Дефект (Намалена Проходимост):</strong></li><ul><li>Бронхиална астма, Хроничен обструктивен бронхит, Емфизем, ХОББ, Бронхиектазии, Кистична фиброза, Бронхиолити.</li></ul><li><strong>Рестриктивен Вентилаторен Дефект (Намален Обем):</strong></li><ul><li><i>Идиопатична белодробна фиброза, Интерстициален пневмонит, Плеврални изливи, Саркоидоза, Торакални деформации, Застойна сърдечна недостатъчност, Нервномускулни нарушения.</i></li></ul></ul><ul><ul><li><em>Забележка:</em> При рестрикция се налага <strong>определяне на статичните белодробни обеми (напр. ТБК)</strong>.</li></ul></ul><hr><h2>Интерпретация и Стадиране</h2><h3>Интерпретация на Спирометричните Показатели</h3><ol><li><strong>Проверка:</strong> Дали ФВК е в границите на референтните стойности.</li><li><strong>Проверка:</strong> Дали ФЕО1 е в границите на референтните стойности.</li><li><strong>Нормален тест:</strong> Ако ФВК и ФЕО1 са в референтните граници.</li><li><strong>Вентилаторно нарушение:</strong> Ако ФВК и/или ФЕО1 са <strong>под долната граница</strong> на референтните стойности.</li><li><strong>Тип Нарушение (по ФЕО₁/ФВК%): при наличие на вентилаторно нарушение</strong></li><ul><li><strong>Рестрикция (вероятна): </strong>ФЕО1/ФВК% е <strong>нормално или увеличено </strong>(изисква ТБК за потвърждение).</li><li><strong>Обструкция:</strong> ФЕО1/ФВК% е <strong>по-ниско от 70%</strong>.</li></ul></ol><h3>Стадиране на Тежестта на Нарушението</h3><p>(Изразява се като % от предвидената стойност, базирана на пол, възраст, ръст)</p><ul><li><strong>Леко:</strong> 70–79% от предвидената стойност</li><li><strong>Умерено:</strong> 60–69% от предвидената стойност</li><li><strong>Умерено тежко:</strong> 50–59% от предвидената стойност</li><li><strong>Тежко:</strong> 35–49% от предвидената стойност</li><li><strong>Много тежко:</strong> &lt; 35% от предвидената стойност</li></ul><hr><h2>Пост-Бронходилататорен Тест (БДТ)</h2><ul><li><strong>Цел:</strong> Определяне дали обструкцията на въздушния поток е <strong>обратима (реверзибилна)</strong>.</li><li><strong>Методика:</strong> Изследване преди и 15–30 мин. след приложение на бронходилататор (напр. 400 мкг b2-агонист или 80 мкг антихолинергик).</li></ul><ul><li><strong>Положителен резултат:</strong> Нарастване на ФЕО1 с повече от <strong>200 мл</strong> спрямо пребронходилататорния ФЕО1 <strong>И/ИЛИ</strong> с <strong>12%</strong> спрямо предвидената стойност.</li></ul><h3>Интерпретация на БДТ</h3><table><thead><tr><th>Заболяване</th><th>Обичаен Резултат</th><th>Забележка</th></tr></thead><tbody><tr><td>ХОББ</td><td>Отрицателен (необратима обструкция).</td><td>Пост-бронходилататорната стойност на ФЕО1 се използва за стадиране на тежестта на ХОББ.</td></tr><tr><td>Бронхиална Астма</td><td>Положителен (обратима обструкция).</td><td>Силно положителен (ФЕО1 може да се удвои) при умерена обструкция.</td></tr><tr><td>Астма (Отрицателен БДТ)</td><td>Може да е отрицателен при:<br> Тежка обструкция (наличие на оток и секрети) <br> Лека/гранична обструкция във фаза на ремисия (ФЕО₁ \"няма накъде повече да нараства\").</td><td></td></tr></tbody></table><hr><h2>Метахолинов Провокационен Тест (МПТ)</h2><h3>Цел</h3><ul><li>Доказване на <strong>бронхиална хиперреактивност (БХР)</strong>, която е патофизиологичен белег на астмата.</li><li>Използва се, когато има клинични симптоми на астма, но основната спирометрия е нормална.</li></ul><h3>Методика</h3><ul><li>Пациентът инхалира <strong>нарастващи концентрации/дози</strong> на <strong>Метахолин</strong> (холинергичен агонист, предизвикващ бронхоконстрикция).</li><li>Спирометрията се повтаря след всяка доза.</li><li>Тестът се прекъсва, когато ФЕО1 спадне с 20% или се достигне максималната доза.</li></ul><h3>Положителен Резултат</h3><ul><li>Измерва се провокативната доза или провокативната концентрация на Метахолин, която води до <strong>спад на ФЕО1 с 20%</strong> спрямо изходната стойност.</li><li>По-ниската доза/концентрация, предизвикваща този спад, означава по-висока степен на БХР.</li></ul><hr><h2>Изследване на Върховия Експираторен Дебит (ВЕД)</h2><p>Извършва се с ВЕД-метър (Peak Flow Meter). Изследването се извършва трикатно, като се анализира най-добрият резултат. Резултатите се приемат за възпроизводими, ако не се различават с повече от <strong>5%</strong> (или 10 L/min) помежду си.</p><h3>Приложение</h3><ul><li>Оценка на <strong>тежестта на астматичния пристъп</strong>.</li><li>Оценка на <strong>отговора към лечение</strong> на астматичния пристъп.</li><li><strong>Амбулаторно мониториране</strong> на болни с бронхиална астма (чрез проследяване на вариабилността).</li></ul><h3>Оценка на тежестта на пристъпа (по ВЕД % предвидено)</h3><ul><li>ВЕД&gt; 80% – <strong>Лек</strong> пристъп</li><li>ВЕД 60–80% – <strong>Средно тежък</strong> пристъп</li><li>ВЕД &lt; 60% – <strong>Тежък</strong> пристъп</li><li>ВЕД&lt; 30% – <strong>Заплашващ живота</strong> пристъп</li></ul><h3>Класификация на Бронхиална Астма по Тежест (по ВЕД)</h3><table><tbody><tr><td><strong><font color=\"#588157\">Форма на Астмата</font></strong></td><td><strong><font color=\"#588157\">ВЕД (% предвидено)</font></strong></td><td><strong><font color=\"#588157\">Вариабилност (%)</font></strong></td></tr><tr><td><strong>Лека интермитентна</strong></td><td>ВЕД &gt;= 80%</td><td>ВЕД &lt; 20%</td></tr><tr><td><strong>Лека персистираща</strong></td><td>ВЕД &gt;= 80%</td><td>ВЕД 20-30%</td></tr><tr><td><strong>Умерено тежка</strong></td><td>ВЕД 60-80%</td><td>ВЕД &gt; 30%</td></tr><tr><td><strong>Тежка</strong></td><td>ВЕД &lt;= 80%</td><td>ВЕД &gt; 30%</td></tr></tbody></table><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\"><br><br><link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\"><style></p><p>    body { </p><p>      font-family: \"Open Sans\", Arial, sans-serif; </p><p>      max-width: 1550px; </p><p>      margin: 0.5rem auto; </p><p>      padding: 0 1rem; </p><p>      line-height: 1.8; </p><p>      color: #1f2937; </p><p>    }</p><p>    h1, h2, h3, h4 { </p><p>      font-weight: 600; </p><p>      margin-top: 0.8em;</p><p>      margin-bottom: 0.3em;</p><p>      color: #3a5a40;</p><p>    }</p><p>    h1 { font-size: 1.5em; }</p><p>    h2 { font-size: 1.3em; }</p><p>    h3 { font-size: 1.1em; }</p><p>    h4 { font-size: 1.05em; }</p><p>    h3 + h4 { margin-top: 0.3em; }</p><p>    p { </p><p>      margin: 0.7em 0; </p><p>      white-space: pre-wrap;</p><p>    }</p><p>    p + ul, p + ol { margin-top: -0.5em; }</p><p>    h1 + p, h2 + p, h3 + p, h4 + p,</p><p>    h1 + ul, h2 + ul, h3 + ul, h4 + ul,</p><p>    h1 + ol, h2 + ol, h3 + ol, h4 + ol { </p><p>      margin-top: 0.1em; </p><p>    }</p><p>    ul, ol { </p><p>      margin: 0.3em 0; </p><p>      padding-left: 1.5em; </p><p>    }</p><p>    li { margin: 0.15em 0; }</p><p>    ul ul { list-style-type: circle; }</p><p>    ul ul ul { list-style-type: square; }</p><p>    strong { font-weight: 600; }</p><p>    em { font-style: italic; }</p><p>    code { </p><p>      background: rgba(218, 215, 205, 0.3); </p><p>      padding: 2px 6px; </p><p>      border-radius: 3px; </p><p>      font-family: \"Courier New\", monospace; </p><p>      font-size: 0.9em; </p><p>    }</p><p>    pre {</p><p>      background: rgba(255, 255, 255, 0.5);</p><p>      padding: 12px;</p><p>      border-radius: 4px;</p><p>      overflow-x: auto;</p><p>      margin: 0.5em 0;</p><p>      font-family: \"Courier New\", monospace;</p><p>    }</p><p>    pre code {</p><p>      background: none;</p><p>      padding: 0;</p><p>    }</p><p>    blockquote {</p><p>      border-left: 3px solid #a3b18a;</p><p>      padding-left: 1em;</p><p>      margin: 0.5em 0;</p><p>      font-style: italic;</p><p>      color: #3a5a40;</p><p>    }</p><p>    table { </p><p>      border-collapse: collapse; </p><p>      margin: 0.75em 0; </p><p>      width: 100%; </p><p>      table-layout: auto;</p><p>    }</p><p>    th, td { </p><p>      border: 1px solid rgba(146, 64, 14, 0.35); </p><p>      padding: 6px 10px; </p><p>      text-align: left; </p><p>      vertical-align: top;</p><p>    }</p><p>    thead th { </p><p>      background: rgba(196, 127, 9, 0.08); </p><p>      font-weight: 600; </p><p>    }</p><p>    tbody tr:nth-child(odd) { </p><p>      background: rgba(146, 64, 14, 0.03); </p><p>    }</p><p>   .markdown-body img { </p><p>      max-width: 100%; </p><p>      height: auto; </p><p>    }</p><p>    a { </p><p>      color: #a3b18a; </p><p>      text-decoration: underline; </p><p>    }</p><p>    a:hover {</p><p>      color: #d97706;</p><p>    }</p><p>    @media (max-width: 768px) {</p><p>      body {</p><p>        max-width: 100%;</p><p>        margin: 0.5rem 0;</p><p>        padding: 0 0.5rem;</p><p>        font-size: 16px;</p><p>      }</p><p>      h1 { font-size: 1.3em; }</p><p>      h2 { font-size: 1.1em; }</p><p>      h3 { font-size: 1em; }</p><p>      p { margin: 0.5em 0; }</p><p>      ul, ol { padding-left: 1.2em; }</p><p>      li { margin: 0.1em 0; }</p><p>      table { font-size: 0.9em; }</p><p>      th, td { padding: 4px 6px; }</p><p>    }</p><p>  </style><link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\"><style></p><p>    body { </p><p>      font-family: \"Open Sans\", Arial, sans-serif; </p><p>      max-width: 1550px; </p><p>      margin: 0.5rem auto; </p><p>      padding: 0 1rem; </p><p>      line-height: 1.8; </p><p>      color: #1f2937; </p><p>    }</p><p>    h1, h2, h3, h4 { </p><p>      font-weight: 600; </p><p>      margin-top: 0.8em;</p><p>      margin-bottom: 0.3em;</p><p>      color: #3a5a40;</p><p>    }</p><p>    h1 { font-size: 1.5em; }</p><p>    h2 { font-size: 1.3em; }</p><p>    h3 { font-size: 1.1em; }</p><p>    h4 { font-size: 1.05em; }</p><p>    h3 + h4 { margin-top: 0.3em; }</p><p>    p { </p><p>      margin: 0.7em 0; </p><p>      white-space: pre-wrap;</p><p>    }</p><p>    p + ul, p + ol { margin-top: -0.5em; }</p><p>    h1 + p, h2 + p, h3 + p, h4 + p,</p><p>    h1 + ul, h2 + ul, h3 + ul, h4 + ul,</p><p>    h1 + ol, h2 + ol, h3 + ol, h4 + ol { </p><p>      margin-top: 0.1em; </p><p>    }</p><p>    ul, ol { </p><p>      margin: 0.3em 0; </p><p>      padding-left: 1.5em; </p><p>    }</p><p>    li { margin: 0.15em 0; }</p><p>    ul ul { list-style-type: circle; }</p><p>    ul ul ul { list-style-type: square; }</p><p>    strong { font-weight: 600; }</p><p>    em { font-style: italic; }</p><p>    code { </p><p>      background: rgba(218, 215, 205, 0.3); </p><p>      padding: 2px 6px; </p><p>      border-radius: 3px; </p><p>      font-family: \"Courier New\", monospace; </p><p>      font-size: 0.9em; </p><p>    }</p><p>    pre {</p><p>      background: rgba(255, 255, 255, 0.5);</p><p>      padding: 12px;</p><p>      border-radius: 4px;</p><p>      overflow-x: auto;</p><p>      margin: 0.5em 0;</p><p>      font-family: \"Courier New\", monospace;</p><p>    }</p><p>    pre code {</p><p>      background: none;</p><p>      padding: 0;</p><p>    }</p><p>    blockquote {</p><p>      border-left: 3px solid #a3b18a;</p><p>      padding-left: 1em;</p><p>      margin: 0.5em 0;</p><p>      font-style: italic;</p><p>      color: #3a5a40;</p><p>    }</p><p>    table { </p><p>      border-collapse: collapse; </p><p>      margin: 0.75em 0; </p><p>      width: 100%; </p><p>      table-layout: auto;</p><p>    }</p><p>    th, td { </p><p>      border: 1px solid rgba(146, 64, 14, 0.35); </p><p>      padding: 6px 10px; </p><p>      text-align: left; </p><p>      vertical-align: top;</p><p>      height: 24px;</p><p>      line-height: 1.2;</p><p>    }</p><p>    thead th { </p><p>      background: rgba(196, 127, 9, 0.08); </p><p>      font-weight: 600; </p><p>    }</p><p>    tbody tr:nth-child(odd) { </p><p>      background: rgba(146, 64, 14, 0.03); </p><p>    }</p><p>   .markdown-body img { </p><p>      max-width: 100%; </p><p>      height: auto; </p><p>    }</p><p>    a { </p><p>      color: #a3b18a; </p><p>      text-decoration: underline; </p><p>    }</p><p>    a:hover {</p><p>      color: #d97706;</p><p>    }</p><p>    @media (max-width: 768px) {</p><p>      body {</p><p>        max-width: 100%;</p><p>        margin: 0.5rem 0;</p><p>        padding: 0 0.5rem;</p><p>        font-size: 16px;</p><p>      }</p><p>      h1 { font-size: 1.3em; }</p><p>      h2 { font-size: 1.1em; }</p><p>      h3 { font-size: 1em; }</p><p>      p { margin: 0.5em 0; }</p><p>      ul, ol { padding-left: 1.2em; }</p><p>      li { margin: 0.1em 0; }</p><p>      table { font-size: 0.9em; }</p><p>      th, td { padding: 4px 6px; }</p><p>    }</p><p>  </style><hr style=\"text-align: center; border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\"><h1>Бронхоскопия</h1><h3>Дефиниция:  </h3><p>Бронхоскопията е процедура, при която бронхоскоп се въвежда през трахеята за оглед на големите и средни дихателни пътища и за вземане на материал за изследване.</p><h3><strong>Видове бронхоскопия</strong>:</h3><p><strong>Според използвания бронхоскоп:</strong></p><ul><li><strong>1. Ригидна бронхоскопия:</strong></li><ul><li>Използва се за <strong>т</strong><strong>ерапевтични/интервенционални</strong> процедури и <strong>контрол на спешни състояния:</strong></li><ul><li><strong>Отстраняване на големи/заседнали чужди тела</strong>.</li><li><strong>Овладяване на масивна хемоптиза</strong> (кръвохрачене).</li><li><strong>Механично дебулкиране</strong><strong> на централни тумори</strong>.</li><li>Поставяне на <strong>стентове</strong><strong> </strong>и <strong>дилатация на стенози</strong>.</li></ul><li>Извършва се обикновено под <strong>обща анестезия</strong>.</li></ul><li><strong>2. Флексибилна бронхоскопия (фибробронхоскопия):</strong></li><ul><li>Използва се за<strong> диагностика</strong><strong> </strong>и достигане до периферните дихателни пътища:</li><ul><li><strong>Рутинен оглед</strong>.</li><li><strong>Биопсия </strong>и бронхоалвеоларен лаваж.</li><li>Отстраняване на малки чужди тела/секрети.</li></ul><li>Извършва се обикновено под <strong>локална анестезия</strong>.</li></ul></ul><p><strong>Според целта:</strong></p><ul><li><strong>Диагностична бронхоскопия </strong>– вземане на материал за цитологично, хистологично или микробиологично изследване.</li><li><strong>Терапевтична бронхоскопия</strong> – аспирация и лаваж при запушване на дихателните пътища от гъсти секрети или чуждо тяло.</li></ul><h3><strong>Диагностични процедури при различни процеси:</strong></h3><ul><li><strong>Централен ендобронхиален процес:</strong></li><ul><li>Четкова биопсия</li><li>Щипкова биопсия</li><li>Катетър биопсия</li></ul><li><strong>Централен перибронхиален процес:</strong></li><ul><li><strong>Трансбронхиална пункционна биопсия</strong> -&nbsp;каналана бронхоскопа се прекарва игла, с която се пробива стената на бронха и сеаспирира материал от туморни маси или лимфни възли прилежащи на бронха.</li><li><strong>Трансбронхиална белодробна биопсия</strong>&nbsp;-&nbsp;с подходяща щипка се прониквапрез канала на бронхоскопа и се взема материал от периферията набелия дроб. Методът е подходящ при дифузните интерстициални болести.</li></ul><li><strong>Периферен процес:</strong></li><ul><li><strong>Бронхо-алвеоларен лаваж</strong> – инсталиране и обратно аспириране на затоплен (37°C) физиологичен разтвор за цитологично и микробиологично изследване.</li><li><strong>Трансторакална тънкоиглена аспирационна биопсия</strong> (не е част от бронхоскопия) - използват се тънки игли, с които се прониква през гръдната стена до изменението под рентгенов контрол (или КАТ, Ехографски) и се аспирира. Материалът се изследва цитологично и микробиологично.</li></ul></ul><h3><strong>Показания за бронхоскопия:</strong></h3><ul><li>Подозрение за <strong>белодробен рак</strong></li><li><strong>Белодробна инфекция</strong></li><li><strong>Интерстициално белодробно заболяване</strong></li><li><strong>Отстраняване на чуждо тяло</strong></li><li><strong>Кръвохрачене</strong></li><li><strong>Неясна кашлица</strong> или <strong>задух</strong></li></ul><p><strong>Противопоказания за бронхоскопия:</strong></p><ul><li><strong>Абсолютни противопоказания:</strong> не съществуват.</li><li><strong>Относителни противопоказания:</strong></li><ul><li>Кислородна сатурация &lt; 90%</li><li>PaO2 &lt; 8 kPa</li><li>FEV1 &lt; 40%</li><li>Тромбоцити &lt; 50 000/mm³</li><li>Пресен миокарден инфаркт (в последните 6 седмици)</li><li>Уремия</li><li>Пулмонална хипертония</li><li>Имуносупресия, предразполагаща към хеморагия</li><li>Чернодробни заболявания</li></ul></ul><hr><h2>Индуциран спутум</h2><h3><strong>Определение:</strong>  </h3><p>Метод за получаване на храчка (спутум) за цитологично или микробиологично изследване при пациенти <strong>без спонтанна експекторация</strong>.</p><h3><strong>Процедура:</strong></h3><ol><li>Пациентът <strong>изплаква устата си и измива зъбите си</strong>, за да се намали оралната контаминация.</li><li>Прилага се <strong>инхалаторен Salbutamol</strong> за постигане на бронходилатация.</li><li>След това се <strong>небулизира (превръща се в пара) хипертоничен физиологичен разтвор</strong> чрез лицева маска с контейнер.</li><li>Полученият <strong>спутум се отделя в стерилен съд</strong> и се транспортира до лабораторията за изследване.</li></ol><p><a href=\"https://www.youtube.com/watch?v=CztDIt5nen8\">Induced Sputum Collection Video</a></p><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\"><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\"><h1 style=\"text-align: center\">Кръвно-газов анализ (КГА)</h1><h2>Дефиниция</h2><p>КГА е диагностичен метод за оценка на газовия обмен и киселинно-алкалното равновесие (КАР) чрез измерване на:</p><ul><li>парциалното налягане на кислорода (PaO2)</li><li>парциалното налягане на въглеродния диоксид (PaCO2)</li><li>концентрацията на бикарбонат (HCO3-)</li><li>pH на кръвта</li></ul><hr><h2>Вземане на проба</h2><ul><li>Първи избор: артериална пункция на a. radialis</li><li>Алтернатива: проба от ушна висулка след подготовка с ревулзивна паста</li></ul><hr><h2>Нормални референтни стойности (здрави индивиди, стайна среда, ниво на морето)</h2><table><tbody><tr><td><strong><font color=\"#588157\">Параметър</font></strong></td><td><strong><font color=\"#588157\">Норма</font></strong></td></tr><tr><td>PaO2</td><td>90–95 mmHg</td></tr><tr><td>PaCO2</td><td>36–44 mmHg</td></tr><tr><td>pH</td><td>7.36–7.44</td></tr><tr><td>HCO3-</td><td>22–26 mmol/L</td></tr></tbody></table><hr><h2>Хипоксемия (↓ PaO2)</h2><p><strong>Определение:</strong>  </p><p>Хипоксемията представлява понижение на парциалното налягане на кислорода в артериалната кръв (PaO2).  </p><p>Може да доведе до хипоксия — намалено снабдяване на тъканите с кислород.</p><p><strong>Причини за хипоксемия</strong></p><p><strong>1. Намалено парциално налягане на вдишания кислород</strong></p><ul><li>Обструкция на дихателните пътища</li><li>Престой на голяма надморска височина (височинна болест)</li></ul><p><strong>2. Смутена алвеоло-капилярна дифузия</strong></p><ul><li>Емфизем</li><li>Белодробна фиброза</li></ul><p><strong>3. Хиповентилация</strong></p><ul><li>Потискане на дихателния център (ЦНС)</li><li>Невро-мускулни заболявания</li><li>Пневмоторакс</li><li>Плеврален излив</li></ul><p><strong>4. Артерио-венозен шънт (смесване на венозна и артериална кръв)</strong></p><ul><li>Атектелаза</li><li>Белодробен инфаркт</li><li>Пневмония</li><li>Вродени сърдечни пороци</li></ul><hr><h2>Влияние на компонентите върху pH</h2><ul><li><strong>Респираторна (PaCO2)</strong> – бързо променящ се компонент:</li><ul><li>Хиперкапния (повишен PaCO2) → респираторна ацидоза (↓ pH)</li><li>Хипокапния (понижен PaCO2) → респираторна алкалоза (↑ pH)</li></ul><li><strong>Метаболитна (HCO3-)</strong> – регулира се чрез бъбреците; задържане или загуба на HCO3- води до метаболитна алкалоза или ацидоза</li></ul><hr><h2>Основни респираторно-метаболитни състояния</h2><table><tbody><tr><td><strong>Състояние</strong></td><td><strong>pH</strong></td><td><strong>PaCO2</strong></td><td><strong>HCO3-</strong></td></tr><tr><td>Респираторна ацидоза</td><td>↓</td><td>↑</td><td>↔ (↑ при хронична)</td></tr><tr><td>Респираторна алкалоза</td><td>↑</td><td>↓</td><td>↔ (↓ при хронична)</td></tr><tr><td>Метаболитна ацидоза</td><td>↓</td><td>↓ компенсаторно</td><td>↓</td></tr><tr><td>Метаболитна алкалоза</td><td>↑</td><td>↑ компенсаторно</td><td>↑</td></tr></tbody></table><hr><h2>Причини / клинични ситуации</h2><p><strong>Респираторна ацидозa (↑PaCO2) -  при хронични респираторни заболявания с хиповентилация се стига до развитието на хиперкапния с респираторна ацидоза:</strong></p><ul><li>ХОББ</li><li>Заболявания на гръдната стена и белия дроб</li><li>Заболявания на ЦНС</li></ul><p><strong>Респираторна алкалоза (↓ PaCO2) - при състояния с хипервентилация се стига до развитието на хипокапния с респираторна алкалоза:</strong></p><ul><li>Хипервентилация (психогенна, болка, хипоксемия)</li><li>Бронхиална астма</li><li>Кардиална астма</li><li>Заболявания на ЦНС</li><li>Лечение с хормони - катехоламини, прогестерон, хипертиеродизъм</li><li>Интоксиакция със салицилати</li><li>Артериална хипоксия</li><li>Чернодробни заболявания</li><li>Фебрилитет</li></ul><p><strong>Метаболитна ацидоза (↓ HCO3-):</strong></p><ul><li>Кетоацидоза</li><li>Лактатна ацидоза</li><li>Остра и хронична бъбречна недостатъчност</li><li>Интоксикации (метанол, етилен гликол, салицилати)</li><li>Диарии, чревни фистули</li><li>Гладуване</li></ul><p><strong>Метаболитна алкалоза (↑ HCO3-):</strong></p><ul><li>Загуба на стомашни сокове (повръщане, дренажи)</li><li>Лечение с диуретици</li></ul><hr><h2>Смесени и комплексни нарушения (често в клиниката)</h2><p>Смесените нарушения могат да дават нормален pH, но с отклонения в PaCO2 и HCO3-.</p><p>Смесените форми са <strong>често срещани в клиничната практика</strong> и изискват внимателен анализ на всички показатели (pH, PaCO2, HCO3-, PaO2).</p><h3>Основни видове и примери</h3><table><tbody><tr><td><strong><font color=\"#588157\">Нарушение</font></strong></td><td><strong><font color=\"#588157\">Характеристика</font></strong></td><td><strong><font color=\"#588157\">Примери (клинични ситуации)</font></strong></td></tr><tr><td><strong>Респираторна ацидоза +<br> метаболитна ацидоза</strong></td><td>↓ pH<br> ↑ PaCO2<br> ↓ HCO3-</td><td>Сърдечен арест<br>Мултиорганна недостатъчност<br>Интоксикации</td></tr><tr><td><strong>Респираторна aкалоза + <br> метаболитна алкалоза</strong></td><td>↑ pH<br>↓  PaCO2<br>↑ HCO3-</td><td>Цироза с диуретици <br> Бременност с повръщане <br> Хипервентилация при ХОББ</td></tr><tr><td><strong>Респираторна ацидоза +<br> метаболитна алкалоза</strong></td><td>pH в нормални стойности<br> ↑ PaCO2<br> ↑ HCO3-</td><td>ХОББ с диуретици<br>Повръщане<br> Тежка хипокалиемия</td></tr><tr><td><strong>Респираторна алкалоза +<br> метаболитна ацидоза</strong></td><td>pH в нормални стойности<br> ↓ PaCO2<br> ↓ HCO3-</td><td>Сепсис<br>Чернодробна недостатъчност<br>Интоксикация със салицилати<br>Бъбречна недостатъчност с ХСН или пневмония</td></tr><tr><td><strong>Метаболитна ацидоза +<br> метаболитна алкалоза</strong></td><td>pH в нормални стойности<br>HCO3- в нормални стойности</td><td>Уремия или повръщане кетоацидоза с повръщане <br> Диуретици</td></tr></tbody></table><h3>Практически бележки</h3><ul><li>Анализирай PaO2, PaCO2, HCO3- и pH заедно.</li><li>Оцени дали промяната е остра или хронична (компенсация).</li><li>При съмнение за смесени нарушения – търси клиничната причина.</li></ul><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\"><br><br><hr style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(115, 163, 114)\"><h1 style=\"text-align: center\">🩻 План за разчитане на рентгенография на гръдна клетка</h1><h2>Преди всичко:</h2><ul><li>Определете <strong>вида на рентгенографията</strong> – гръдна клетка (РА проекция, право положение, легнал, АР и т.н.).</li><li>Проверете дали <strong>името на снимката и заявката съвпадат</strong>.</li><li>Обърнете внимание на <strong>възрастта и пола на пациента</strong>.</li></ul><hr><h2>I. Ориентация на снимката</h2><ul><li>Проверете дали <strong>ляво и дясно</strong> са правилно отбелязани.</li></ul><h2>II. Центриране на снимката</h2><ul><li>Всички части на белите дробове трябва да се виждат - върхове, основи, косто-диафрагмални синуси (КДС)</li><li>Да се виждат <strong>и двата купола на диафрагмата</strong>.</li><li><strong>Стерналните ръбове на ключиците</strong> трябва да са на еднакво разстояние от спинозните израстъци → симетрична графия.</li><li><strong>Ръцете на пациента</strong> трябва да са абдуцирани, за да не се наслагват скапулите върху белодробните полета.</li></ul><h2>III. Техническо качество на снимката</h2><p>(важи основно за снимки на плака, не за дигитални рентгенографии)</p><ul><li><strong>Нормална експонация:</strong> през медиастиналната сянка се виждат първите 4 торакални прешлена.</li><li><strong>Субекспонирана графия (бял филм):</strong> не се вижда нито един прешлен през медиастинума.</li><li><strong>Преекспонирана графия (черен филм):</strong> виждат се всички прешлени.</li></ul><h2>IV. Оценка на торакалните структури</h2><h3>1. Куполи на диафрагмите</h3><ul><li><strong>Позиция:</strong> нормално на нивото на 5–6 междуребрие (по предната част на ребрата).</li><ul><li>Лявата обикновено е с до 2.5 cm по-ниска от дясната.</li><li>При ~10% от хората са на едно ниво.</li></ul><li><strong>Очертания:</strong> резки, гладки, проследими от край до край.</li><li><strong>Косто-диафрагмални синуси:</strong> остри, добре видими.</li><li><strong>Субдиафрагмално пространство:</strong> без свободен въздух или патологични засенчвания (напр. калцификати).</li></ul><h3>2. Медиастинум</h3><ul><li><strong>Позиция на медиастиналната сянка:</strong> централно разположена – около 1/3 надясно и 2/3 наляво от срединната линия.</li><li><strong>Ширина:</strong> нормалната медиастинална сянка се описва като неразширена.</li><li><strong>Очертания:</strong> резки и гладки.</li><li><strong>Форма:</strong> с нормални дъги.</li><li><strong>Сърдечна сянка:</strong></li><ul><li>Размер – до 50% от ширината на торакса (кардио-торакален индекс, КТИ ≤ 0.5).</li><li>Описание на сърдечните дъги – нормални или с увеличен конвекситет, допълнителни дъги (напр. двойно-контуриране на дъгата на дясно предсърдие от уголемено ляво предсърдие).</li></ul><li><strong>Трахея:</strong> централно разположена, неразширена; ъгълът на бифуркацията е остър ≤ 70°.</li></ul><h2>3. Хилуси</h2><ul><li><strong>Хилусна точка:</strong> мястото, където горно-дяловата белодробна вена пресича долно-дяловата артерия.</li><li><strong>Позиция:</strong> между 2-ро и 4-то ребро (по преден контур).</li><ul><li>Левият е малко по-висок (до 1 cm) от десния.</li></ul><li><strong>Структура:</strong> само съдове.</li><li><strong>Размер на долнодяловите белодробни артерии:</strong> до 17 mm.</li></ul><h2>4. Белодробни полета</h2><ul><li>Нормално се виждат само <strong>сенки на съдове и ребра</strong>.</li><li>Понякога се виждат централните бронхиални клонове като „пръстенчета“ (при ортограден изглед).</li><li><strong>Всяка</strong> сянка, която не произлиза от тези структури, трябва да бъде описана.</li><li><strong>Зони:</strong></li><ul><li>Горно белодробно поле – над 2-ро ребро отпред</li><li>Средно белодробно поле – между 2-ро и 4-то ребро отпред</li><li>Долно белодробно поле – под 4-то ребро отпред</li></ul><li><strong>Белодробен съдов рисунък:</strong></li><ul><li>Хиперемия – твърде много съдове</li><li>Олигемия – намален брой съдове</li><li>Венозна конгестия – при сърдечна недостатъчност</li><li>Рязка промяна в калибъра – патологична</li></ul></ul><h2>5. Костни структури</h2><ul><li>Всички ребра са налице, без фрактури.</li><li>Без патологични сенки или лезии по костите.</li></ul><h2>6. Меки тъкани</h2><ul><li>Хомогенни, без патологични сенки.</li><li>Проверете за <strong>мастектомия</strong> или други промени.</li></ul><p><img src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-11/text-editor-images/2026/03/1773252277297-image.png\" alt=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-11/text-editor-images/2026/03/1773252277297-image.png\" data-original-src=\"https://files.coursebook.lol/%D0%9F%D0%B0%D0%B8%D1%81%D0%B8%D0%B9/2026-03-11/text-editor-images/2026/03/1773252277297-image.png\" data-width=\"70\" style=\"width: auto; max-width: 70%; height: auto; display: block\"></p><hr><h2>Причини за солитарен белодробен нодул</h2><ul><li><strong>Неоплазии</strong></li><ul><li><em></em>Малигнени</li></ul></ul><ul><li>Бронхогенен карцином</li><li>Солитарна белодробна метастаза</li><li>Лимфом</li><li>Карциноиден тумор (бронхиален или периферен)</li></ul><ul><li><strong>Доброкачествени</strong></li><ul><li>Белодробен хамартом</li><li>Хондром</li></ul></ul><ul><li><strong>Възпалителни причини</strong></li><ul><li>Гранулом</li><li>Белодробен абсцес</li><li>Ревматоиден нодул (ревматоиден артрит, грануломатоза на Вегенер)</li><li>Възпалителен псевдотумор (плазмоклетъчен гранулом)</li><li>Кръгла пневмония</li><li>Туберкулом (ТБК)</li><li>Мицетом (аспергилом и др.)</li></ul><li><strong>Вродени причини</strong></li><ul><li>Артерио-венозна малформация</li><li>Белодробна киста</li><li>Бронхиална атрезия с изпълнен бронх (секрет)</li></ul><li><strong>Други причини</strong></li><ul><li>Инфаркт на белия дроб</li><li>Интрапулмонален лимфен възел</li><li>Бронхиален секрет</li><li>Белодробен хематом</li><li>Белодробна амилоидоза</li><li>Нормален конфлуенс на белодробните вени</li></ul><li><strong>Мимикьори (фалшиви нодули)</strong></li><ul><li>Сянка на мамилата</li><li>Кожна лезия (бенка, брадавица)</li><li>Излив по малкия интерлобарен процеп</li><li>Костна фрактура или друга костна лезия</li></ul></ul><br>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\[', right: '\\]', display: true},\n    {left: '\\(', right: '\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>";
